import { IMessageComposer } from '@nitrots/nitro-renderer';

/**
 * Sends a taxi request for a given roomId + virtualRoomId.
 * Mirrors the server-side TaxiRequestEvent packet structure.
 */
export class TaxiRequestComposer implements IMessageComposer<number[]> {
    private _data: number[];

    constructor(roomId: number, virtualRoomId: number) {
        this._data = [roomId, virtualRoomId];
        console.log(
            `[📤] TaxiRequestComposer packet sent → Room ${roomId}, vRoom ${virtualRoomId}`
        );
    }

    public getMessageArray(): number[] {
        return this._data;
    }

    public dispose(): void {
        this._data = [];
    }
}
